const chatData = $input.first().json;
const sessionId = chatData.sessionId ?? chatData.session_id ?? 'default';
const chatInput = (chatData.chatInput ?? chatData.message ?? '').trim();
const lower = chatInput.toLowerCase();

const directMap = {'1':1,'one':1,'first':1,'2':2,'two':2,'second':2,'3':3,'three':3,'third':3};
const isSelection = directMap[lower] !== undefined;
const selectedIndex = isSelection ? directMap[lower] : null;

const greetRe = /^(hi|hello|hey|yo|sup|salam|good (morning|afternoon|evening))\b[\s,!.]*(how are you|how r u|hru|what'?s up|kya haal hai)?[\s!.?]*$/i;
const thanksRe = /^(thanks|thank you|thx|shukriya)[\s!.?]*$/i;
const isGreet = (greetRe.test(lower) || thanksRe.test(lower)) && !isSelection;

const resetWords = ['reset','start over','clear','new search','restart','clear filters'];
const isReset = resetWords.includes(lower);

const moreWords = ['more','show more','next','next 3','next page'];
const isMore = moreWords.includes(lower);

const skipAI = isSelection || isGreet || isReset || isMore;
let fastIntent = null;
if (isSelection) fastIntent = 'show_detail';
else if (isGreet) fastIntent = 'greet';
else if (isReset) fastIntent = 'reset';
else if (isMore) fastIntent = 'show_more';

return [{ json: { userMessage: chatInput, sessionId, skipAI, fastIntent, selectedIndex } }];

const parseInput = $('02 | Parse Input').first().json;
const rows = $('03 | Read Session').all();
const row = rows.length > 0 ? rows[0].json : {};
const previousState = row?.state ?? {};
const lastResults = row?.last_results ?? [];
const cityCache = row?.city_cache ?? {};
const chatHistory = row?.chat_history ?? [];
const resultOffset = row?.result_offset ?? 0;

const sessionId = parseInput.sessionId;
const userMessage = parseInput.userMessage;

if (parseInput.skipAI) {
  return [{ json: { skipAI: true, fastIntent: parseInput.fastIntent, selectedIndex: parseInput.selectedIndex, previousState, lastResults, cityCache, chatHistory, resultOffset, sessionId, userMessage } }];
}

const systemPrompt = `You are a smart real estate assistant with PERFECT memory.

YOUR JOB:
1. Read RECENT CONVERSATION and CURRENT STATE carefully - these are preferences already collected
2. Extract NEW info from the user message
3. Merge: keep ALL non-null state values, only update fields user explicitly mentions
4. Output merged state + intent

INTENT RULES:
- greet: user says hi, hello, hey, thanks, or any small talk
- search_property: property_type AND city are BOTH non-null in merged state
- gather_info: property_type OR city is still null after merging
- weather_query: user explicitly asks about weather or temperature
- show_detail: user selects a result by number or ordinal
- reset: user wants to start over, clear filters, or begin a new search

PROPERTY TYPES (use exact spelling): Apartment, Villa, Studio, Condo, House
STUDIO RULE: if type is Studio, set bedrooms to 0
PRICE: between X and Y => min_price:X max_price:Y | under X => max_price:X | at least X => min_price:X
BEDROOMS: 2 bedroom => bedrooms:2
CITY: always normalize (new york => New York, seattle => Seattle, lahore => Lahore)

CRITICAL RULES:
- ALWAYS copy ALL non-null fields from previous_state into updated_state FIRST
- NEVER wipe a field unless user explicitly says to change it or asks to reset
- For gather_info: still output all known fields, just set clarification_needed
- For greet: set greeting_message to a warm short response
- Amenities are NOT filterable: if mentioned set amenity_note, do not add to state

OUTPUT - valid JSON only, no markdown:
{
  "updated_state": {"property_type": null, "min_price": null, "max_price": null, "city": null, "state": null, "bedrooms": null},
  "intent": "greet|search_property|gather_info|show_detail|weather_query|reset",
  "selected_index": null,
  "weather_city": null,
  "clarification_needed": null,
  "amenity_note": null,
  "greeting_message": null
}`;

const historyText = chatHistory.slice(-6).map(h => h.role + ': ' + h.text).join('\n');
const userPrompt = 'RECENT CONVERSATION:\n' + (historyText || '(none)') + '\n\nCURRENT STATE:\n' + JSON.stringify(previousState, null, 2) + '\n\nUser: "' + userMessage + '"\n\nReturn JSON only.';

return [{ json: { skipAI: false, systemPrompt, userPrompt, previousState, lastResults, cityCache, chatHistory, resultOffset, sessionId, userMessage } }];

const bp = $('04 | Build Prompt').first().json;
const inp = $input.first().json;
const previousState = bp.previousState ?? {};
const lastResults = bp.lastResults ?? [];
const cityCache = bp.cityCache ?? {};
const chatHistory = bp.chatHistory ?? [];
const resultOffset = bp.resultOffset ?? 0;
const sessionId = bp.sessionId;
const userMessage = bp.userMessage ?? '';

function fallbackExtract(msg) {
  const out = { updated_state: {}, intent: 'gather_info', clarification_needed: null };
  const m = msg.toLowerCase();
  const types = { apartment: 'Apartment', villa: 'Villa', studio: 'Studio', condo: 'Condo', house: 'House' };
  for (const k in types) if (m.includes(k)) out.updated_state.property_type = types[k];
  const bed = m.match(/(\d+)\s*(bed|bedroom|br)/);
  if (bed) out.updated_state.bedrooms = Number(bed[1]);
  const between = m.match(/between\s*\$?([\d,]+)\s*(?:and|-|to)\s*\$?([\d,]+)/);
  const under = m.match(/(?:under|below|max)\s*\$?([\d,]+)/);
  const over = m.match(/(?:at least|above|over|min)\s*\$?([\d,]+)/);
  if (between) {
    out.updated_state.min_price = Number(between[1].replace(/,/g, ''));
    out.updated_state.max_price = Number(between[2].replace(/,/g, ''));
  } else {
    if (under) out.updated_state.max_price = Number(under[1].replace(/,/g, ''));
    if (over) out.updated_state.min_price = Number(over[1].replace(/,/g, ''));
  }
  const cityM = msg.match(/\bin\s+([A-Za-z][A-Za-z ]{1,30})/i);
  if (cityM) out.updated_state.city = cityM[1].trim();
  if (m.includes('weather') || m.includes('temperature')) out.intent = 'weather_query';
  return out;
}

// FAST PATH: no AI was called
if (bp.skipAI === true) {
  const intent = bp.fastIntent;
  let mergedState = { ...previousState };
  let outResults = lastResults;
  if (intent === 'reset') { mergedState = {}; outResults = []; }
  return [{ json: {
    intent,
    selected_index: bp.selectedIndex ?? null,
    weather_city: mergedState.city ?? null,
    clarification_needed: null,
    amenity_note: null,
    greeting_message: null,
    aiDown: false,
    mergedState,
    stateB64: Buffer.from(JSON.stringify(mergedState)).toString('base64'),
    lastResults: outResults,
    cityCache,
    chatHistory,
    resultOffset,
    sessionId,
    userMessage
  } }];
}

// AI PATH (with regex fallback if Groq failed)
let parsed = {};
let aiDown = false;
const raw = inp.choices?.[0]?.message?.content ?? null;
if (raw) {
  try {
    const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (e) {
    parsed = fallbackExtract(userMessage);
    aiDown = true;
  }
} else {
  parsed = fallbackExtract(userMessage);
  aiDown = true;
}

const next = parsed.updated_state ?? {};
let mergedState = { ...previousState };
for (const k in next) {
  if (next[k] !== null && next[k] !== undefined && next[k] !== '') mergedState[k] = next[k];
}
if (mergedState.city) {
  mergedState.city = mergedState.city.split(',')[0].trim().replace(/\b\w/g, c => c.toUpperCase());
}
if (mergedState.property_type === 'Studio') mergedState.bedrooms = 0;

let intent = parsed.intent ?? 'gather_info';
if (intent === 'gather_info' && mergedState.property_type && mergedState.city) intent = 'search_property';

let outResults = lastResults;
if (intent === 'reset') { mergedState = {}; outResults = []; }

return [{ json: {
  intent,
  selected_index: parsed.selected_index ?? null,
  weather_city: parsed.weather_city ?? mergedState.city ?? null,
  clarification_needed: parsed.clarification_needed ?? null,
  amenity_note: parsed.amenity_note ?? null,
  greeting_message: parsed.greeting_message ?? null,
  aiDown,
  mergedState,
  stateB64: Buffer.from(JSON.stringify(mergedState)).toString('base64'),
  lastResults: outResults,
  cityCache,
  chatHistory,
  resultOffset: 0,
  sessionId,
  userMessage
} }];

const w = $input.first().json;
const d = $('07 | Parse + Merge State').first().json;
const s = d.mergedState ?? {};
if (!w || w.cod === undefined || Number(w.cod) !== 200) {
  return [{ json: { output: 'Could not fetch weather' + (d.weather_city ? ' for ' + d.weather_city : '') + '. Try again with a city name, e.g. "weather in Lahore".' } }];
}
const city = w.name || 'the city';
const temp = Math.round(w.main?.temp) ?? 'N/A';
const feels = Math.round(w.main?.feels_like) ?? 'N/A';
const desc = w.weather?.[0]?.description || 'N/A';
const hum = w.main?.humidity ?? 'N/A';
const wind = Math.round(w.wind?.speed) ?? 'N/A';
let ctx = '';
if (s.property_type) {
  ctx = '\n\nStill tracking your ' + s.property_type + ' search' + (s.city ? ' in ' + s.city : '') + ' — just say the word to continue!';
}
const output = [
  'Weather in ' + city, '',
  'Temperature : ' + temp + '°C (feels like ' + feels + '°C)',
  'Conditions  : ' + desc.charAt(0).toUpperCase() + desc.slice(1),
  'Humidity    : ' + hum + '%',
  'Wind        : ' + wind + ' m/s'
].join('\n') + ctx;
return [{ json: { output } }];

const d = $input.first().json;
const s = d.mergedState ?? {};
const cityCache = d.cityCache ?? {};
const amenityNote = d.amenity_note ?? null;
const TTL = 30 * 60 * 1000;
const now = Date.now();
const cacheKey = s.city ? s.city.toLowerCase().trim() : null;
const entry = cacheKey ? (cityCache[cacheKey] ?? null) : null;
const isFresh = entry && (now - entry.cachedAt) < TTL;
return [{ json: {
  hasCacheHit: !!isFresh,
  cachedRecords: isFresh ? (entry.records ?? []) : [],
  state: s,
  cacheKey,
  amenity_note: amenityNote,
  cityCache
} }];

const data = $input.first().json;
const s = data.state ?? {};
let recs = [...(data.cachedRecords ?? [])];
if (s.property_type) recs = recs.filter(r => r.property_type === s.property_type);
if (s.min_price != null) recs = recs.filter(r => Number(r.price) >= Number(s.min_price));
if (s.max_price != null) recs = recs.filter(r => Number(r.price) <= Number(s.max_price));
if (s.bedrooms != null) recs = recs.filter(r => Number(r.bedrooms) === Number(s.bedrooms));
const top10 = recs.sort((a, b) => Number(a.price) - Number(b.price)).slice(0, 10);
return [{ json: { properties: top10, state: s, fromCache: true, amenity_note: data.amenity_note ?? null, cityCache: data.cityCache ?? {} } }];

const cacheData = $('12 | Check Cache').first().json;
const s = cacheData.state ?? {};
const amenityNote = cacheData.amenity_note ?? null;
const cityCache = { ...(cacheData.cityCache ?? {}) };
const records = $input.all().map(i => i.json).filter(r => r && r.id);
if (s.city && records.length > 0) {
  const key = s.city.toLowerCase().trim();
  cityCache[key] = { records, cachedAt: Date.now() };
}
return [{ json: { properties: records, state: s, fromCache: false, amenity_note: amenityNote, cityCache } }];

const d = $('07 | Parse + Merge State').first().json;
const data = $input.first().json;
const props = data.properties ?? [];
const s = data.state ?? {};
const amenityNote = data.amenity_note ?? null;
const cityCache = data.cityCache ?? {};

let output;
if (props.length === 0) {
  const c = [
    s.property_type,
    s.city ? 'in ' + s.city : null,
    s.bedrooms != null ? s.bedrooms + ' bedrooms' : null,
    (s.min_price && s.max_price) ? '$' + Number(s.min_price).toLocaleString() + '-$' + Number(s.max_price).toLocaleString() : null
  ].filter(Boolean).join(' ');
  output = 'No matches found for ' + (c || 'your search') + '. Try adjusting your filters or type "reset" to start over.';
} else {
  const shown = props.slice(0, 3);
  const total = props.length;
  let intro = 'Found ' + total + ' ' + (s.property_type ? s.property_type + (total > 1 ? 's' : '') : 'propert' + (total > 1 ? 'ies' : 'y'));
  if (s.city) intro += ' in ' + s.city;
  if (s.bedrooms != null) intro += ' | ' + s.bedrooms + ' Bed';
  if (s.min_price && s.max_price) intro += ' | $' + Number(s.min_price).toLocaleString() + '-$' + Number(s.max_price).toLocaleString();
  if (data.fromCache) intro += ' (cached)';
  const lines = shown.map((p, i) => {
    const beds = Number(p.bedrooms) === 0 ? 'Studio' : p.bedrooms + ' Bed';
    const amens = Array.isArray(p.amenities) && p.amenities.length ? p.amenities.join(', ') : 'N/A';
    return (i + 1) + '. ' + p.property_type + ' — ' + p.city + ', ' + p.state + ' | $' + Number(p.price).toLocaleString() + '/mo | ' + beds + ' | Amenities: ' + amens;
  });
  output = intro + '\n\n' + lines.join('\n');
  if (amenityNote) output += '\n\nNote: ' + amenityNote;
  output += '\n\nType 1, 2, or 3 to see full details.';
  if (total > 3) output += " Type 'more' for the next page.";
}
if (d.aiDown) output += '\n\n(Quick mode: AI was busy, basic keyword matching used.)';
return [{ json: { output, lastResults: props, cityCache, resultOffset: 0 } }];

const d = $('07 | Parse + Merge State').first().json;
const s = d.mergedState ?? {};
const clarification = d.clarification_needed ?? null;
let output;
if (s.property_type && !s.city) {
  output = 'Great choice! Which city are you looking for a ' + s.property_type + ' in?';
} else if (!s.property_type && s.city) {
  output = s.city + ' is a great area! What type of property are you looking for?\n\nApartment | Studio | Villa | House | Condo';
} else {
  output = clarification ?? 'What type of property are you looking for?\n\nApartment | Studio | Villa | House | Condo';
}
if (d.aiDown) output += '\n\n(Quick mode: AI was busy, basic keyword matching used.)';
return [{ json: { output } }];

const d = $('07 | Parse + Merge State').first().json;
const lastResults = d.lastResults ?? [];
const offset = d.resultOffset ?? 0;
const idx = offset + ((d.selected_index ?? 1) - 1);
if (lastResults.length === 0) {
  return [{ json: { output: 'Please search for a property first, then type 1, 2, or 3 to see full details.' } }];
}
const prop = lastResults[idx] ?? null;
if (!prop) {
  return [{ json: { output: 'Invalid selection. Please type 1, 2, or 3 from the listed results.' } }];
}
const beds = Number(prop.bedrooms) === 0 ? 'Studio' : prop.bedrooms + ' Bedroom';
const amens = Array.isArray(prop.amenities) && prop.amenities.length ? prop.amenities.join(', ') : 'N/A';
const output = [
  '--- Property Details ---', '',
  prop.property_type + ' in ' + prop.city + ', ' + prop.state,
  'Price     : $' + Number(prop.price).toLocaleString() + '/mo',
  'Size      : ' + beds,
  'Status    : Available',
  'Amenities : ' + amens, '',
  "Want to search another city, type 'more' for other results, or 'reset' to start fresh?"
].join('\n');
return [{ json: { output } }];

const d = $('07 | Parse + Merge State').first().json;
const s = d.mergedState ?? {};
let output = d.greeting_message ?? 'Hello! I am your property assistant. Tell me what type of property you are looking for and which city!';
if (s.property_type || s.city) {
  output += '\n\nStill tracking: ' + [s.property_type, s.city ? 'in ' + s.city : null].filter(Boolean).join(' ') + '. Say the word to continue!';
}
return [{ json: { output } }];

return [{ json: { output: 'All filters cleared! Fresh start.

What type of property are you looking for?

Apartment | Studio | Villa | House | Condo' } }];

const d = $('07 | Parse + Merge State').first().json;
const lastResults = d.lastResults ?? [];
const newOffset = (d.resultOffset ?? 0) + 3;
const page = lastResults.slice(newOffset, newOffset + 3);
if (lastResults.length === 0) {
  return [{ json: { output: 'No active search. Tell me a property type and city first!', resultOffset: 0 } }];
}
if (page.length === 0) {
  return [{ json: { output: 'No more results for this search. Try adjusting filters or a new city.', resultOffset: d.resultOffset ?? 0 } }];
}
const lines = page.map((p, i) => {
  const beds = Number(p.bedrooms) === 0 ? 'Studio' : p.bedrooms + ' Bed';
  const amens = Array.isArray(p.amenities) && p.amenities.length ? p.amenities.join(', ') : 'N/A';
  return (i + 1) + '. ' + p.property_type + ' — ' + p.city + ', ' + p.state + ' | $' + Number(p.price).toLocaleString() + '/mo | ' + beds + ' | Amenities: ' + amens;
});
let output = 'More results (' + (newOffset + 1) + '-' + (newOffset + page.length) + ' of ' + lastResults.length + '):\n\n' + lines.join('\n');
output += '\n\nType 1, 2, or 3 to see full details.';
if (lastResults.length > newOffset + 3) output += " Type 'more' for the next page.";
return [{ json: { output, resultOffset: newOffset } }];

const d = $('07 | Parse + Merge State').first().json;
const branch = $input.first().json;
const output = branch.output ?? 'Sorry, something went wrong. Please try again.';
const lastResults = branch.lastResults ?? d.lastResults ?? [];
const cityCache = branch.cityCache ?? d.cityCache ?? {};
const resultOffset = branch.resultOffset ?? d.resultOffset ?? 0;

const hist = [...(d.chatHistory ?? [])];
if (d.userMessage) hist.push({ role: 'user', text: String(d.userMessage).slice(0, 300) });
hist.push({ role: 'assistant', text: String(output).slice(0, 300) });
const chatHistory = hist.slice(-12);

const b64 = (obj) => Buffer.from(JSON.stringify(obj)).toString('base64');

return [{ json: {
  output,
  sessionId: d.sessionId,
  historyB64: b64(chatHistory),
  lastResultsB64: b64(lastResults),
  cityCacheB64: b64(cityCache),
  resultOffset
} }];
